export{apiFetch,handleApiError,apiGet,apiPost,apiPut,apiDelete}from '../shared/api.js';const API_BASE_URL=typeof SUPABASE_URL!=='undefined' ? SUPABASE_URL : 'https://pzcgvfhppglzfjavxuid.supabase.co';export async function apiFetch(endpoint,options={}){const url=endpoint.startsWith('http')? endpoint : `${API_BASE_URL}${endpoint}`;const config={...options,headers:{'Content-Type': 'application/json',...(options.headers||{})}};try{const response=await fetch(url,config);if(!response.ok){const error=await response.json().catch(()=>({message: 'API error'}));throw new Error(error.message||`HTTP ${response.status}`);}if(response.status===204){return null;}return await response.json();}catch(error){Logger.error('[API Error]',{endpoint,error: error.message});throw error;}}export function handleApiError(error,options={}){const{showNotification=true,message='Có lỗi xảy ra'}=options;Logger.error('[API Error]',error.message);if(showNotification&&typeof window!=='undefined'){if(window.Toast?.error){window.Toast.error(message);}else if(window.Alert?.error){window.Alert.error('Lỗi',message);}}return null;}export function apiGet(endpoint,headers={}){return apiFetch(endpoint,{method: 'GET',headers});}export function apiPost(endpoint,data={},headers={}){return apiFetch(endpoint,{method: 'POST',body: JSON.stringify(data),headers});}export function apiPut(endpoint,data={}){return apiFetch(endpoint,{method: 'PUT',body: JSON.stringify(data)});}export function apiDelete(endpoint){return apiFetch(endpoint,{method: 'DELETE'});}